/**
 *
 * @param domain
 * @param range
 * @param systemconf
 * @param padding
 * @param outerpadding
 * @param type
 * @param index
 * @returns {number}
 */
//extendOuterpadding.js
import { d3_max, d3_merge, d3_extent } from '../../core/d3-constants';
import { DataProcessor } from '../data-processor';
import { d3_scaleOrdinal } from '../d3-constants';
import { correctionParserMap } from '../../scale-parser/axis/correction/correction-parser';

DataProcessor.prototype.extendOuterpadding = function(domain, range, systemconf, padding, outerpadding, type, index) {
    var processor = this,
        chartObj = processor.chartObj;
    range = d3_extent(range); // if (range[0] > range[1]) { range = [range[1], range[0]]; }

    var scaleObj = d3_scaleOrdinal()
        .domain(domain)
        .range(range)
        .paddingInner(padding)
        .paddingOuter(outerpadding);

    let corrections = Object.keys(correctionParserMap).map(_ => chartObj.cache.correction[_ + '-' + type + '-' + index] || [0, 0]),
        totalCorrection = d3_max(d3_merge(corrections));

    if (!totalCorrection) {
        return 0;
    }
    return totalCorrection - (scaleObj(scaleObj.domain()[0]) - scaleObj.range()[0]);
};

export var _outerPaddingCorrection = DataProcessor.extendOuterpadding;
